{
var seed = GetInt(parameters, "seed", context.Seed);
    var cols = Math.Max(2, GetInt(parameters, "cols", 8));
    var rows = Math.Max(2, GetInt(parameters, "rows", 8));
    var gapWidth = GetFloat(parameters, "gapWidth", 0.08f);
    var layout = GetChoice(parameters, "layout", "grid");
    var baseColor = GetColor(parameters, "baseColor", Color.FromRgb(220, 210, 200));
    var gapColor = GetColor(parameters, "gapColor", Color.FromRgb(60, 55, 50));
    var colorVar = GetFloat(parameters, "colorVariation", 0.4f);
    var glossiness = GetFloat(parameters, "glossiness", 0.2f);
    var roundness = GetFloat(parameters, "roundness", 0.2f);
    var brightness = GetFloat(parameters, "brightness", 0f);
    var contrast = GetFloat(parameters, "contrast", 0f);
    var invert = GetBool(parameters, "invert", false);

    var size = context.TileSize;
    var buffer = new PixelBuffer(size, size);

    var bR = baseColor.R / 255f; var bG = baseColor.G / 255f; var bB = baseColor.B / 255f;
    var gR = gapColor.R / 255f; var gG = gapColor.G / 255f; var gB = gapColor.B / 255f;

    // Pre-compute per-tile colors
    var tileColors = new (float r, float g, float b)[cols, rows];
    for (var r = 0; r < rows; r++)
    {
        for (var c = 0; c < cols; c++)
        {
            var hash = HashToUnit(c * 13 + r * 17, seed, 111);
            var hueShift = (hash - 0.5f) * colorVar;
            // Generate a random vibrant color based on seed + position
            var hueAngle = HashToUnit(c * 7 + r * 11, seed + 50, 222) * MathF.PI * 2f;
            var sat = 0.5f + HashToUnit(c * 5 + r * 23, seed + 100, 333) * 0.5f;
            var light = 0.4f + HashToUnit(c * 19 + r * 29, seed + 150, 444) * 0.4f;

            // Simplified HSL to RGB
            var h = hueAngle / (MathF.PI * 2f);
            var (tr, tg, tb) = HslToRgb(h, sat, light);
            // Blend with base color
            tileColors[c, r] = (
                Lerp(bR, tr, colorVar),
                Lerp(bG, tg, colorVar * 0.9f),
                Lerp(bB, tb, colorVar * 0.8f)
            );
        }
    }

    buffer.ParallelForEachPixel((x, y) =>
    {
        var u = (x + 0.5f) / size;
        var v = (y + 0.5f) / size;

        // Determine tile position based on layout
        float tileU, tileV;
        int tileCol, tileRow;

        switch (layout)
        {
            case "brick":
            {
                var brickW = 1f / cols;
                var brickH = 1f / rows;
                var row = (int)(v / brickH);
                var rowOffset = (row % 2) * 0.5f * brickW;
                tileU = ((u + rowOffset) % 1f);
                tileV = v;
                tileCol = (int)((u + rowOffset) / brickW);
                tileRow = (int)(v / brickH);
                // Normalize to 0..1 within tile
                tileU = (tileU - tileCol * brickW) / brickW;
                tileV = (tileV - tileRow * brickH) / brickH;
                tileCol = ((tileCol % cols) + cols) % cols;
                tileRow = ((tileRow % rows) + rows) % rows;
                break;
            }
            case "diamond":
            {
                // Diamond layout: 45° rotated grid
                var ru = u * 0.707f - v * 0.707f;
                var rv = u * 0.707f + v * 0.707f;
                var diamondW = 1f / cols;
                var diamondH = 1f / rows;
                tileCol = (int)((ru + 0.5f) / diamondW);
                tileRow = (int)((rv + 0.5f) / diamondH);
                tileU = ((ru + 0.5f) - tileCol * diamondW) / diamondW;
                tileV = ((rv + 0.5f) - tileRow * diamondH) / diamondH;
                tileCol = ((tileCol % cols) + cols) % cols;
                tileRow = ((tileRow % rows) + rows) % rows;
                break;
            }
            default: // grid
            {
                var cellW = 1f / cols;
                var cellH = 1f / rows;
                tileCol = (int)(u / cellW);
                tileRow = (int)(v / cellH);
                tileU = (u - tileCol * cellW) / cellW;
                tileV = (v - tileRow * cellH) / cellH;
                tileCol = ((tileCol % cols) + cols) % cols;
                tileRow = ((tileRow % rows) + rows) % rows;
                break;
            }
        }

        // Distance to nearest edge (for gap detection)
        var distU = MathF.Min(tileU, 1f - tileU);
        var distV = MathF.Min(tileV, 1f - tileV);

        // Rounded corners
        float edgeDist;
        if (roundness > 0f)
        {
            var cornerDist = MathF.Sqrt(distU * distU + distV * distV);
            var linearDist = MathF.Max(distU, distV);
            edgeDist = Lerp(linearDist, cornerDist, roundness);
        }
        else
        {
            edgeDist = MathF.Min(distU, distV);
        }

        var gapThreshold = gapWidth * 0.5f;
        var isGap = edgeDist < gapThreshold;

        float r, g, b;

        if (isGap)
        {
            // Grout/mortar
            var gapNoise = TileableFractalNoise(
                u * 5f + 50f, v * 5f + 50f,
                Math.Max(1, size / 3), 1, 0.5f, 2f, seed + 200);
            var gapVar = (gapNoise - 0.5f) * 0.06f;
            r = Math.Clamp(gR + gapVar, 0f, 1f);
            g = Math.Clamp(gG + gapVar * 0.9f, 0f, 1f);
            b = Math.Clamp(gB + gapVar * 0.8f, 0f, 1f);

            // Depth shading in gap
            var depthT = 1f - edgeDist / Math.Max(gapThreshold, 0.001f);
            var depth = depthT * 0.2f;
            r = Math.Clamp(r - depth, 0f, 1f);
            g = Math.Clamp(g - depth * 0.9f, 0f, 1f);
            b = Math.Clamp(b - depth * 0.8f, 0f, 1f);
        }
        else
        {
            // Tile interior
            var tc = tileColors[tileCol, tileRow];
            r = tc.r;
            g = tc.g;
            b = tc.b;

            // Subtle highlight at tile edge
            var edgeHighlight = 1f - (edgeDist - gapThreshold) / (0.5f - gapThreshold);
            edgeHighlight = MathF.Max(0f, edgeHighlight);
            edgeHighlight = edgeHighlight * edgeHighlight * 0.15f;

            // Light direction (top-left)
            var lightDir = ((-(tileU - 0.5f) * 0.7f + -(tileV - 0.5f) * 0.7f) + 0.7f) / 1.4f;
            var shade = 0.85f + lightDir * 0.15f;

            r *= shade + edgeHighlight;
            g *= shade + edgeHighlight * 0.9f;
            b *= shade + edgeHighlight * 0.8f;

            // Gloss
            if (glossiness > 0f)
            {
                var gloss = MathF.Pow(MathF.Max(0f, lightDir), 4f) * glossiness * 0.2f;
                r = Math.Clamp(r + gloss, 0f, 1f);
                g = Math.Clamp(g + gloss * 0.95f, 0f, 1f);
                b = Math.Clamp(b + gloss * 0.9f, 0f, 1f);
            }
        }

        // Brightness and contrast
        r = Math.Clamp(r + brightness, 0f, 1f);
        g = Math.Clamp(g + brightness, 0f, 1f);
        b = Math.Clamp(b + brightness, 0f, 1f);

        if (MathF.Abs(contrast) > 0.001f)
        {
            var factor = 1f + contrast;
            r = (r - 0.5f) * factor + 0.5f;
            g = (g - 0.5f) * factor + 0.5f;
            b = (b - 0.5f) * factor + 0.5f;
        }

        if (invert) { r = 1f - r; g = 1f - g; b = 1f - b; }

        buffer.SetPixel(x, y, Math.Clamp(r, 0f, 1f), Math.Clamp(g, 0f, 1f), Math.Clamp(b, 0f, 1f), 1f);
    });

    return buffer;

/// <summary>
/// Converts HSL color to RGB (all values in 0..1 range).
/// </summary>
private static (float r, float g, float b) HslToRgb(float h, float s, float l)
{
    if (s < 0.001f) return (l, l, l);

    h = h - MathF.Floor(h);
    var q = l < 0.5f ? l * (1f + s) : l + s - l * s;
    var p = 2f * l - q;

    float HueToRgb(float t)
    {
        if (t < 0f) t += 1f;
        if (t > 1f) t -= 1f;
        if (t < 1f / 6f) return p + (q - p) * 6f * t;
        if (t < 1f / 2f) return q;
        if (t < 2f / 3f) return p + (q - p) * (2f / 3f - t) * 6f;
        return p;
    }

    return (HueToRgb(h + 1f / 3f), HueToRgb(h), HueToRgb(h - 1f / 3f));
    }
}
